export const sportsCards: SportsCard[] = _cards;

export function getCardsBySlug(slug: string): SportsCard | undefined {
  return sportsCards.find(c => c.slug === slug);
}

export function getCardsBySport(sport: SportsCard['sport']): SportsCard[] {
  return sportsCards.filter(c => c.sport === sport);
}

